        """Nested directories use forward-slash relative paths."""
        sub = tmp_path / "d1" / "d2"
        sub.mkdir(parents=True)
        (sub / "deep.txt").write_text("deep")
        result = scan_tree(tmp_path)
        assert "d1/d2/deep.txt" in result

